def avg_color(colors):
    if not colors:
        return (0, 0, 0)
    r_sum = 0
    g_sum = 0
    b_sum = 0
    for c in colors:
        r_sum += c[0]
        g_sum += c[1]
        b_sum += c[2]
    n = len(colors)
    r_avg = round(r_sum / n)
    g_avg = round(g_sum / n)
    b_avg = round(b_sum / n)
    return (r_avg, g_avg, b_avg)
